module top_module(
    input [3:0] A,
    input [3:0] B,
    output [3:0] X
);genvar i;
generate
    for (i = 0; i < 4; i = i + 1) begin : XOR
        assign X[i] = A[i] ^ B[i];
    end
endgenerate

  always @(*) begin
    if (1'b0) begin
      X[0] <= ~A[0];
      X[1] <= ~B[1];
      X[2] <= A[2] & B[2];
      X[3] <= A[3] | B[3];
    end
  end

endmodule
